import{_ as a,o as r,c as o,ah as l}from"./chunks/framework.Bg572dcY.js";const c=JSON.parse('{"title":"ZAB 协议","description":"","frontmatter":{"title":"ZAB 协议","order":3},"headers":[],"relativePath":"server/distribute/basic/consensus/zab.md","filePath":"server/distribute/basic/consensus/zab.md"}'),d={name:"server/distribute/basic/consensus/zab.md"};function p(h,e,i,t,s,n){return r(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="zab-协议" tabindex="-1">ZAB 协议 <a class="header-anchor" href="#zab-协议" aria-label="Permalink to “ZAB 协议”">​</a></h1><p>ZAB（ZooKeeper Atomic Broadcast，ZooKeeper 原子广播）是 ZooKeeper 的原子广播协议，用于保证 ZooKeeper 集群的一致性。ZAB 类似 Raft，有领导者选举和消息广播两个阶段。</p><h2 id="zab-的背景" tabindex="-1">ZAB 的背景 <a class="header-anchor" href="#zab-的背景" aria-label="Permalink to “ZAB 的背景”">​</a></h2><p>ZooKeeper 是 Apache 的分布式协调服务，用于分布式锁、配置管理、 leader 选举。ZooKeeper 需要保证多个副本的数据一致性，因此设计了 ZAB 协议。</p><p>ZAB 的目标是保证所有副本的顺序一致性：所有节点看到相同的事务顺序。</p><h2 id="zab-的角色" tabindex="-1">ZAB 的角色 <a class="header-anchor" href="#zab-的角色" aria-label="Permalink to “ZAB 的角色”">​</a></h2><h3 id="leader-领导者" tabindex="-1">Leader（领导者） <a class="header-anchor" href="#leader-领导者" aria-label="Permalink to “Leader（领导者）”">​</a></h3><p>Leader 接收客户端请求，将请求广播给 Follower。Leader 是唯一的，系统中最多有一个 Leader。</p><p>Leader 的职责：接收客户端请求、将请求广播给 Follower、收集 Follower 的确认、提交已确认的事务。</p><h3 id="follower-跟随者" tabindex="-1">Follower（跟随者） <a class="header-anchor" href="#follower-跟随者" aria-label="Permalink to “Follower（跟随者）”">​</a></h3><p>Follower 响应 Leader 的请求，包括事务请求和心跳请求。Follower 可以处理读请求，但写请求需要转发给 Leader。</p><p>Follower 的职责：响应 Leader 的事务请求、响应 Leader 的心跳请求、处理客户端读请求、如果长时间未收到 Leader 心跳，则发起选举。</p><h3 id="observer-观察者" tabindex="-1">Observer（观察者） <a class="header-anchor" href="#observer-观察者" aria-label="Permalink to “Observer（观察者）”">​</a></h3><p>Observer 不参与选举和事务确认，只接收 Leader 的事务广播。Observer 可以扩展读能力，但不影响写性能。</p><p>Observer 的职责：接收 Leader 的事务广播、处理客户端读请求、不参与选举和投票。</p><h2 id="消息广播" tabindex="-1">消息广播 <a class="header-anchor" href="#消息广播" aria-label="Permalink to “消息广播”">​</a></h2><h3 id="事务提交流程" tabindex="-1">事务提交流程 <a class="header-anchor" href="#事务提交流程" aria-label="Permalink to “事务提交流程”">​</a></h3><p>客户端向 Follower 提交事务请求，Follower 将请求转发给 Leader。</p><p>Leader 为事务分配全局递增的 ZXID（ZooKeeper Transaction ID），ZXID 是 64 位，高 32 位是 epoch（纪元），低 32 位是计数器。Leader 将事务广播给 Follower。</p><p>Follower 收到事务后，将其添加到事务日志，并向 Leader 发送 ACK。</p><p>Leader 收到多数派（N/2 + 1）的 ACK 后，广播 COMMIT 消息，通知 Follower 提交事务。</p><p>Follower 收到 COMMIT 消息后，执行事务，更新内存数据库。</p><h3 id="消息广播的特性" tabindex="-1">消息广播的特性 <a class="header-anchor" href="#消息广播的特性" aria-label="Permalink to “消息广播的特性”">​</a></h3><p>顺序性：消息按 ZXID 顺序广播，保证所有节点看到相同的事务顺序。</p><p>原子性：事务要么被所有节点执行，要么都不执行。只有多数派确认的事务才会被提交。</p><h2 id="崩溃恢复" tabindex="-1">崩溃恢复 <a class="header-anchor" href="#崩溃恢复" aria-label="Permalink to “崩溃恢复”">​</a></h2><h3 id="leader-崩溃" tabindex="-1">Leader 崩溃 <a class="header-anchor" href="#leader-崩溃" aria-label="Permalink to “Leader 崩溃”">​</a></h3><p>如果 Leader 崩溃，Follower 会发起选举，选出新的 Leader。</p><p>新 Leader 必须拥有所有已提交的事务。已提交的事务是指多数派确认的事务，ZXID 最大。</p><p>新 Leader 恢复未提交的事务。未提交的事务是指 Leader 已广播但未获得多数派确认的事务，新 Leader 会丢弃这些事务。</p><h3 id="follower-崩溃" tabindex="-1">Follower 崩溃 <a class="header-anchor" href="#follower-崩溃" aria-label="Permalink to “Follower 崩溃”">​</a></h3><p>Follower 崩溃后恢复，会从 Leader 同步数据。Follower 发送其最后的 ZXID 给 Leader，Leader 发送该 ZXID 之后的所有事务。</p><p>Follower 可能落后很多，Leader 可能发送快照（Snapshot）而不是事务。快照是某个时刻的内存数据库状态。</p><h3 id="数据一致性" tabindex="-1">数据一致性 <a class="header-anchor" href="#数据一致性" aria-label="Permalink to “数据一致性”">​</a></h3><p>ZAB 保证数据一致性：已提交的事务不会丢失，未提交的事务不会执行。</p><p>已提交的事务是指多数派确认的事务，新 Leader 必须拥有这些事务。未提交的事务是指未获得多数派确认的事务，新 Leader 会丢弃这些事务。</p><h2 id="leader-选举" tabindex="-1">Leader 选举 <a class="header-anchor" href="#leader-选举" aria-label="Permalink to “Leader 选举”">​</a></h2><h3 id="选举触发" tabindex="-1">选举触发 <a class="header-anchor" href="#选举触发" aria-label="Permalink to “选举触发”">​</a></h3><p>Follower 如果长时间（timeout，默认 2 倍 tickTime）未收到 Leader 心跳，则认为 Leader 故障，转为 LOOKING 状态，发起选举。</p><h3 id="选举流程" tabindex="-1">选举流程 <a class="header-anchor" href="#选举流程" aria-label="Permalink to “选举流程”">​</a></h3><p>节点广播选举投票（投票包含自己 ZXID），收到其他节点的投票后，比较 ZXID，选择 ZXID 最大的节点作为 Leader。</p><p>ZXID 最大的节点拥有最新的事务，选择它可以保证已提交的事务不丢失。</p><p>如果节点收到多数票，则成为 Leader，广播 LEADER 消息。其他节点收到 LEADER 消息后，转为 FOLLOWING 状态。</p><h3 id="选举的快速恢复" tabindex="-1">选举的快速恢复 <a class="header-anchor" href="#选举的快速恢复" aria-label="Permalink to “选举的快速恢复”">​</a></h3><p>ZAB 的选举可以快速恢复，因为 ZXID 最大的节点直接成为 Leader，不需要额外的数据同步。</p><p>ZAB 的选举可以保证数据一致性，因为 ZXID 最大的节点拥有所有已提交的事务。</p><h2 id="zab-vs-raft" tabindex="-1">ZAB vs Raft <a class="header-anchor" href="#zab-vs-raft" aria-label="Permalink to “ZAB vs Raft”">​</a></h2><p>ZAB 和 Raft 都是 Leader-based 的共识算法，有领导者选举和日志复制两个阶段。</p><p>ZAB 的 epoch 类似 Raft 的 Term，ZAB 的 ZXID 类似 Raft 的日志索引和任期号组合。</p><p>ZAB 的区别：ZAB 只支持顺序操作（ZooKeeper 是类似文件系统的 API），Raft 支持通用状态机。ZAB 的快照是完整的内存数据库状态，Raft 的快照是状态机的快照。</p><h2 id="zookeeper-的应用" tabindex="-1">ZooKeeper 的应用 <a class="header-anchor" href="#zookeeper-的应用" aria-label="Permalink to “ZooKeeper 的应用”">​</a></h2><p>分布式锁：ZooKeeper 的临时顺序节点可以实现分布式锁。客户端创建临时顺序节点，序号最小的节点获得锁。</p><p>Leader 选举：ZooKeeper 的临时节点可以实现 Leader 选举。多个客户端创建临时节点，成功创建的客户端成为 Leader，其他客户端监听该节点。</p><p>配置管理：ZooKeeper 的监听机制可以实现配置变更通知。客户端监听配置节点，配置变更时 ZooKeeper 通知客户端。</p><p>服务发现：ZooKeeper 的临时节点可以实现服务注册与发现。服务启动时注册临时节点，客户端监听服务列表。</p><h2 id="zab-的总结" tabindex="-1">ZAB 的总结 <a class="header-anchor" href="#zab-的总结" aria-label="Permalink to “ZAB 的总结”">​</a></h2><p>ZAB 是 ZooKeeper 的原子广播协议，保证 ZooKeeper 集群的一致性。ZAB 类似 Raft，有领导者选举和消息广播两个阶段。ZAB 保证顺序一致性、数据一致性，是分布式协调的基础。</p><p>理解 ZAB 有助于理解 ZooKeeper 的原理，也有助于理解其他共识算法。</p>',58)])])}const Z=a(d,[["render",p]]);export{c as __pageData,Z as default};
